def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(point1, point2):
        return np.sqrt(np.sum((point1 - point2) ** 2))

    def calculate_arrival_time(start_pos, end_pos, speed):
        distance = euclidean_distance(start_pos, end_pos)
        return current_time + (distance / speed)

    n = len(unvisited_customers)
    if n == 0:
        return None  # No unvisited customers left; might need to head back to depot

    best_node = None
    min_penalty = float('inf')

    for i in range(n):
        arrival_time = calculate_arrival_time(cur_truck_pos, unvisited_customers[i], truck_speed)
        start_window, end_window = time_windows[i]

        if arrival_time < start_window:
            # Calculate the time penalty for waiting
            wait_time = start_window - arrival_time
            penalty = wait_time
        elif arrival_time > end_window:
            # Large penalty for missing the time window
            penalty = (arrival_time - end_window) * 100  # Adjust the penalty scale as per importance
        else:
            penalty = 0  # Arrives within the time window

        future_time_cost = 0
        # Estimate disruption cost of future routes
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                time_to_customer_from_other_truck = calculate_arrival_time(truck_pos, unvisited_customers[i], truck_speed)
                if time_to_customer_from_other_truck < end_window:
                    future_time_cost += (end_window - time_to_customer_from_other_truck) * 10

        # Total penalty includes future time costs
        total_penalty = penalty + future_time_cost

        # Select node with the minimum penalty
        if total_penalty < min_penalty:
            min_penalty = total_penalty
            best_node = i

    return best_node

