import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def distance(a, b):
        return np.linalg.norm(a - b)

    def time_to_window_end(time_now, end, speed, travel_distance):
        arrival_time = time_now + (travel_distance / speed)
        if arrival_time < end:
            return max(0, end - arrival_time)
        else:
            return float('inf')  # Arrival not possible before window closes

    if not unvisited_customers:
        return None  # All customers visited; consider staying or returning to depot

    unvisited_indices = list(range(len(unvisited_customers)))
    scores = []

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_dist = distance(cur_truck_pos, customer_pos)
        window_start, window_end = time_windows[idx]

        # Calculate the time penalty for arriving before or after the time window
        wait_if_early = max(0, window_start - current_time - travel_dist / truck_speed)
        miss_penalty_if_late = time_to_window_end(current_time, window_end, truck_speed, travel_dist)

        if miss_penalty_if_late == float('inf'):
            # Impossible to reach before window closes; heavy penalty
            score = float('inf')
        else:
            # Score is primarily based on waiting and penalty for missing the window
            score = travel_dist + wait_if_early + miss_penalty_if_late

        scores.append(score)

    # Find the minimum score (best candidate)
    min_score_idx = np.argmin(scores)

    if scores[min_score_idx] == float('inf'):
        # If best option is still impossible, consider waiting at current position
        return None

    best_node = unvisited_indices[min_score_idx]
    return best_node
